import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Header: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'About', path: '/about' },
    { name: 'Services', path: '/services' },
    { name: 'Contact', path: '/contact' },
  ];

  const isActive = (path: string) => location.pathname === path;

  return (
    <header className="sticky top-0 z-50 bg-[#1e3a5f] shadow-lg border-b border-[#1e3a5f]/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          <Link to="/" className="flex items-center space-x-2">
            <div className="bg-[#0d9488] p-1.5 rounded-lg">
              <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M2.166 4.999A11.954 11.954 0 0010 1.944 11.954 11.954 0 0017.834 5c.11.65.166 1.32.166 2.001 0 5.225-3.34 9.67-8 11.317C5.34 16.67 2 12.225 2 7c0-.682.057-1.35.166-2.001zm11.541 3.708a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
              </svg>
            </div>
            <span className="text-xl font-bold text-white tracking-tight">GUARDIANS <span className="text-[#0d9488]">INSURANCE</span></span>
          </Link>

          {/* Desktop Nav */}
          <nav className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`text-sm font-medium transition-colors ${
                  isActive(link.path) ? 'text-[#0d9488]' : 'text-gray-300 hover:text-white'
                }`}
              >
                {link.name}
              </Link>
            ))}
            <button className="bg-[#0d9488] hover:bg-[#0b7a6e] text-white px-5 py-2 rounded-full text-sm font-semibold transition-all shadow-md">
              Login
            </button>
          </nav>

          {/* Mobile menu button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="text-gray-300 hover:text-white focus:outline-none"
            >
              <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                {isOpen ? (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                ) : (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                )}
              </svg>
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Nav */}
      {isOpen && (
        <div className="md:hidden bg-[#1e293b] border-t border-gray-700 animate-fade-in-down">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className={`block px-3 py-2 rounded-md text-base font-medium ${
                  isActive(link.path) ? 'bg-[#0d9488] text-white' : 'text-gray-300 hover:bg-gray-700 hover:text-white'
                }`}
              >
                {link.name}
              </Link>
            ))}
            <button className="w-full text-left px-3 py-2 rounded-md text-base font-medium bg-[#0d9488] text-white mt-2">
              Login
            </button>
          </div>
        </div>
      )}
    </header>
  );
};

export default Header;

import React, { useState } from 'react';

const FloatingActionButton: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const phoneNumber = '+961 70 123 456';
  const cleanNumber = phoneNumber.replace(/\s/g, '');

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen && (
        <div className="absolute bottom-16 right-0 mb-2 w-48 bg-[#1e293b] rounded-xl shadow-2xl overflow-hidden border border-[#0d9488]/30 animate-bounce-in">
          <a
            href={`tel:${cleanNumber}`}
            className="flex items-center px-4 py-3 hover:bg-[#0d9488]/10 text-gray-200 border-b border-gray-700 transition-colors"
          >
            <span className="mr-3">📞</span>
            <span className="text-sm font-medium">Call Us</span>
          </a>
          <a
            href={`https://wa.me/${cleanNumber.replace('+', '')}`}
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center px-4 py-3 hover:bg-[#0d9488]/10 text-gray-200 border-b border-gray-700 transition-colors"
          >
            <span className="mr-3">💬</span>
            <span className="text-sm font-medium">WhatsApp</span>
          </a>
          <a
            href={`sms:${cleanNumber}`}
            className="flex items-center px-4 py-3 hover:bg-[#0d9488]/10 text-gray-200 transition-colors"
          >
            <span className="mr-3">✉️</span>
            <span className="text-sm font-medium">SMS</span>
          </a>
        </div>
      )}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-14 h-14 bg-[#0d9488] hover:bg-[#0b7a6e] text-white rounded-full flex items-center justify-center shadow-2xl transform transition-transform hover:scale-110 active:scale-95 z-50 focus:outline-none"
      >
        <svg
          className={`w-6 h-6 transition-transform duration-300 ${isOpen ? 'rotate-45' : ''}`}
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
        </svg>
      </button>
    </div>
  );
};

export default FloatingActionButton;

import React, { useState } from 'react';
import { SERVICES_DATA } from '../constants';
import { Service } from '../types';

const Services: React.FC = () => {
  const [selectedService, setSelectedService] = useState<Service | null>(null);

  const openModal = (service: Service) => {
    setSelectedService(service);
    document.body.style.overflow = 'hidden';
  };

  const closeModal = () => {
    setSelectedService(null);
    document.body.style.overflow = 'auto';
  };

  return (
    <div className="flex flex-col">
      {/* Header */}
      <section className="bg-[#1e3a5f] py-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-4xl md:text-5xl font-bold text-white mb-6">Our Protection Plans</h1>
          <p className="text-xl text-gray-300 max-w-3xl mx-auto">
            Explore our comprehensive range of insurance products designed to provide total security.
          </p>
        </div>
      </section>

      {/* Grid Section */}
      <section className="py-20 bg-[#0f172a]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {SERVICES_DATA.map((service) => (
              <div 
                key={service.id} 
                className="bg-[#1e293b] rounded-3xl overflow-hidden border border-gray-800 hover:border-[#0d9488]/40 transition-all hover:shadow-2xl flex flex-col h-full group"
              >
                <div className="h-60 overflow-hidden relative">
                  <img src={service.image} alt={service.title} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                  <div className="absolute top-4 left-4 bg-white/10 backdrop-blur-md rounded-full w-12 h-12 flex items-center justify-center text-2xl border border-white/20">
                    {service.icon}
                  </div>
                </div>
                <div className="p-8 flex flex-col flex-grow">
                  <h3 className="text-2xl font-bold text-white mb-4">{service.title}</h3>
                  <p className="text-gray-400 mb-8 flex-grow leading-relaxed">
                    {service.shortDescription}
                  </p>
                  <button 
                    onClick={() => openModal(service)}
                    className="w-full bg-[#1e3a5f] hover:bg-[#0d9488] text-white py-4 rounded-xl font-bold transition-all flex items-center justify-center group"
                  >
                    View Details
                    <svg className="w-5 h-5 ml-2 transform group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8l4 4m0 0l-4 4m4-4H3" />
                    </svg>
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Service Modal */}
      {selectedService && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center px-4 overflow-hidden">
          <div 
            className="absolute inset-0 bg-black/80 backdrop-blur-sm animate-fade-in" 
            onClick={closeModal}
          ></div>
          <div className="bg-[#1e293b] w-full max-w-4xl max-h-[90vh] rounded-3xl shadow-2xl overflow-y-auto relative z-10 animate-scale-in border border-gray-700">
            <button 
              onClick={closeModal}
              className="absolute top-6 right-6 p-2 rounded-full bg-gray-900/50 hover:bg-gray-800 text-white z-20"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>

            <div className="flex flex-col lg:flex-row">
              <div className="lg:w-1/2 h-64 lg:h-auto overflow-hidden">
                <img src={selectedService.image} alt={selectedService.title} className="w-full h-full object-cover" />
              </div>
              <div className="lg:w-1/2 p-8 lg:p-12">
                <div className="inline-block px-4 py-1 rounded-full bg-[#0d9488]/20 text-[#0d9488] text-sm font-bold mb-6">
                  {selectedService.icon} SERVICE PLAN
                </div>
                <h2 className="text-4xl font-bold text-white mb-6">{selectedService.title}</h2>
                <div className="prose prose-invert text-gray-300 mb-10 text-lg leading-relaxed">
                  <p>{selectedService.fullDescription}</p>
                </div>
                <div className="space-y-4">
                  <button className="w-full bg-[#0d9488] hover:bg-[#0b7a6e] text-white py-4 rounded-xl font-bold text-lg shadow-xl transition-all">
                    Get a Free Quote
                  </button>
                  <p className="text-center text-sm text-gray-500">
                    No credit card required for initial quote
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Services;

import React, { useEffect } from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import Header from './components/Header';
import Footer from './components/Footer';
import FloatingActionButton from './components/FloatingActionButton';
import Home from './pages/Home';
import About from './pages/About';
import Services from './pages/Services';
import Contact from './pages/Contact';

// ScrollToTop component to reset scroll position on route change
const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

const App: React.FC = () => {
  return (
    <Router>
      <ScrollToTop />
      <div className="flex flex-col min-h-screen">
        <Header />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/about" element={<About />} />
            <Route path="/services" element={<Services />} />
            <Route path="/contact" element={<Contact />} />
            {/* Fallback to home */}
            <Route path="*" element={<Home />} />
          </Routes>
        </main>
        <Footer />
        <FloatingActionButton />
      </div>
    </Router>
  );
};

export default App;

