// --- Controller ---
const render = () => {
  const app = document.getElementById('app');
  if (!app) return;

  let view = '';
  switch (currentPage) {
    case 'about': view = AboutView(); break;
    case 'services': view = ServicesView(); break;
    case 'contact': view = ContactView(); break;
    default: view = HomeView();
  }

  app.innerHTML = `
    ${Header()}
    <main class="animate-fade">${view}</main>
    ${Footer()}
    ${FAB()}
  `;
  window.scrollTo({ top: 0, behavior: 'instant' });
};

// Global Nav Logic
(window as any).navigate = (page: string) => {
  currentPage = page;
  isMenuOpen = false;
  render();
};

(window as any).toggleMenu = () => {
  isMenuOpen = !isMenuOpen;
  render();
};

(window as any).toggleFab = () => {
  isFabOpen = !isFabOpen;
  render();
};

(window as any).handleContact = (e: Event) => {
  e.preventDefault();
  alert("Thank you! Our team will contact you shortly.");
  (e.target as HTMLFormElement).reset();
};

(window as any).openServiceModal = (id: string) => {
  const service = SERVICES.find(s => s.id === id);
  if (!service) return;

  const modalRoot = document.getElementById('modal-root');
  if (!modalRoot) return;

  document.body.classList.add('modal-open');
  modalRoot.innerHTML = `
    <div class="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div class="absolute inset-0 bg-black/80 backdrop-blur-sm animate-fade" onclick="closeModal()"></div>
      <div class="bg-[#1e293b] w-full max-w-4xl max-h-[90vh] rounded-3xl shadow-2xl overflow-y-auto relative z-10 animate-scale border border-white/10">
        <button onclick="closeModal()" class="absolute top-6 right-6 p-2 rounded-full bg-white/5 hover:bg-white/10 text-white z-20">✕</button>
        <div class="flex flex-col md:flex-row">
          <div class="md:w-1/2 h-64 md:h-auto"><img src="${service.img}" class="w-full h-full object-cover"/></div>
          <div class="md:w-1/2 p-10">
            <div class="text-[#0d9488] font-bold text-sm uppercase mb-4 tracking-widest">${service.icon} Insurance Plan</div>
            <h2 class="text-4xl font-bold text-white mb-6">${service.title}</h2>
            <p class="text-gray-300 leading-relaxed text-lg mb-10">${service.full}</p>
            <button class="w-full bg-[#0d9488] text-white py-5 rounded-2xl font-black text-xl hover:bg-[#0b7a6e] transition-all" onclick="closeModal(); navigate('contact')">GET A QUOTE</button>
          </div>
        </div>
      </div>
    </div>
  `;
};

(window as any).closeModal = () => {
  const modalRoot = document.getElementById('modal-root');
  if (modalRoot) modalRoot.innerHTML = '';
  document.body.classList.remove('modal-open');
};

// --- Init ---
document.addEventListener('DOMContentLoaded', () => {
  render();
});

