interface Message {
  role: 'user' | 'model';
  text: string;
}

const LiveChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Hello! I am your Guardians AI assistant. How can I help protect your future today?' }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: 'You are an expert insurance consultant for Guardians Insurance, a 100% Lebanese-owned firm based in Beirut. You are helpful, professional, and empathetic. You provide information about Home, Car, Medical, Life, Travel, and Business insurance in Lebanon. Keep responses concise and informative.',
        },
      });

      // Send the whole history for context
      const response = await chat.sendMessageStream({ message: userMessage });

      let fullResponse = '';
      setMessages(prev => [...prev, { role: 'model', text: '' }]);

      for await (const chunk of response) {
        fullResponse += chunk.text;
        setMessages(prev => {
          const newMessages = [...prev];
          newMessages[newMessages.length - 1].text = fullResponse;
          return newMessages;
        });
      }
    } catch (error) {
      console.error("Gemini Error:", error);
      setMessages(prev => [...prev, { role: 'model', text: 'I apologize, I am having trouble connecting to our servers. Please try again or call us at +961 70 123 456.' }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-24 z-[60]">
      {/* Chat Window */}
      {isOpen && (
        <div className="absolute bottom-20 right-0 w-[350px] md:w-[400px] h-[500px] bg-white rounded-3xl shadow-2xl flex flex-col overflow-hidden border border-gray-100 animate-fade-in-up">
          {/* Header */}
          <div className="bg-[#1e3a5f] p-5 flex justify-between items-center text-white">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-[#0d9488] rounded-lg flex items-center justify-center text-xs">AI</div>
              <div>
                <p className="font-bold text-sm leading-none">Guardians Expert</p>
                <p className="text-[10px] text-teal-300 mt-1 uppercase tracking-widest font-bold">Online Now</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:text-teal-400">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" strokeWidth="2"/></svg>
            </button>
          </div>

          {/* Messages */}
          <div ref={scrollRef} className="flex-grow overflow-y-auto p-6 space-y-4 bg-[#f8fafc]">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-4 rounded-2xl text-sm leading-relaxed ${
                  m.role === 'user' 
                  ? 'bg-[#1e3a5f] text-white rounded-tr-none shadow-md' 
                  : 'bg-white text-gray-700 border border-gray-100 rounded-tl-none shadow-sm'
                }`}>
                  {m.text || <span className="animate-pulse">...</span>}
                </div>
              </div>
            ))}
            {isTyping && !messages[messages.length-1].text && (
               <div className="flex justify-start">
                 <div className="bg-white p-4 rounded-2xl rounded-tl-none border border-gray-100 shadow-sm">
                   <div className="flex space-x-1">
                     <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce"></div>
                     <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                     <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                   </div>
                 </div>
               </div>
            )}
          </div>

          {/* Input */}
          <form onSubmit={handleSend} className="p-4 bg-white border-t border-gray-100 flex space-x-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask about our plans..."
              className="flex-grow p-3 bg-gray-50 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#0d9488]"
            />
            <button 
